import{_ as e,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F15_關係人交易與利益輸送風險.md"}'),t={name:"審計報告庫/財務審計/6239_力成/20260617/F15_關係人交易與利益輸送風險.md"};function l(n,a,h,s,d,_){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="f15-關係人交易與利益輸送風險-財務審計專家報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務審計專家報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務審計專家報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：關係人銷貨169.7億（佔營收22.6%），主為Kioxia（148.9億，法人董事）。帳期與一般客戶一致，AR無備抵損失，屬產業鏈深度整合正常往來。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年最新年報</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>2025年關係人銷貨169.7億（佔營收22.6%），較2024年181.0億略減-6.3%，其中Kioxia Corporation佔148.9億（87.7%）。關係人進貨僅7.6億（佔營收1.0%），關係人應收帳款51.7億（佔總AR 28%），遠低於銷貨佔比22.6%，顯示關係人付款速度優於一般客戶。關係人合約資產9.7億（+41.3% YoY）反映Kioxia訂單增量。關聯企業（元成蘇州、晶成能源）交易極小（銷貨0.015億、進貨0，僅加工費0.77億），無異常資金往來。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="交易規模與定價檢驗" tabindex="-1">交易規模與定價檢驗 <a class="header-anchor" href="#交易規模與定價檢驗" aria-label="Permalink to &quot;交易規模與定價檢驗&quot;">​</a></h3><p>Kioxia為力成最大客戶且為法人董事，符合IFRS定義的「實質關係人」。關係人銷貨22.6%屬高佔比，需關注。但以下因素緩解風險：(1)定價：年報聲明「按一般交易條件及價格辦理，收款條件為月結30-150天」，與非關係人客戶一致；(2)付款：關係人AR 51.7億，較2024年57.2億下降-9.5%，付款紀律優於一般客戶（非關係人AR增31.4%）；(3)備抵：關係人AR未提列備抵損失，反映Kioxia信用品質極高（全球NAND大廠）；(4)Kioxia的訂單佔比逐年下降（2023年未揭露但2024年161.1億→2025年148.9億），集中度緩步改善。</p><h3 id="子公司利益輸送檢查" tabindex="-1">子公司利益輸送檢查 <a class="header-anchor" href="#子公司利益輸送檢查" aria-label="Permalink to &quot;子公司利益輸送檢查&quot;">​</a></h3><p>力成對子公司超豐（持股43%）及Tera Probe（持股12%+49%合計61%）之交易已於合併報表中沖銷。關聯企業交易：元成蘇州（持股~100%權益法）交易極小，晶成能源（持股8%）僅預付投資款1.33億（股權買賣合約9.38億，第一期款）。資金貸與：對新加坡子公司及日本子公司資金貸與合計58.2億，屬100%持股子公司間的短期營運週轉，利率1.45-2.0%符合市場行情。無背書保證。主要管理階層薪酬3.7億（佔營收0.05%），較2024年4.6億下降，無異常。</p><h3 id="治理結構檢查" tabindex="-1">治理結構檢查 <a class="header-anchor" href="#治理結構檢查" aria-label="Permalink to &quot;治理結構檢查&quot;">​</a></h3><p>年報揭露Kioxia為實質關係人（法人董事），力成董事長蔡篤恭。力成與Kioxia的交易歷史悠久（20年以上），Kioxia為力成長期策略股東。此類「客戶兼股東」的關係在台灣半導體供應鏈中常見（如台積電/蘋果、日月光/聯發科），屬產業鏈深度整合，非利益輸送。會計師出具無保留意見，關係人交易經外部稽核。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>Kioxia客戶集中度偏高</strong>：佔關係人銷貨88%、總營收約20%。若Kioxia因NAND景氣反轉或供應鏈重組轉單，對力成營收衝擊可達150億級別。</li><li><strong>價格公平性無法完全驗證</strong>：年報揭露關係人進貨「無其他適當交易對象可資比較」，關聯企業交易定價透明度不足。雖會計師已查核仍存理論風險。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>關係人付款紀律優於一般客戶</strong>：關係人AR減9.5%、非關係人AR增31.4%，顯示Kioxia付款效率良好，無備抵損失。</li><li><strong>不存在子公司虧損補貼</strong>：關聯企業（元成蘇州、晶成能源）交易極小，無關聯企業收取高於市價費用。資金貸與利率1.45-2.0%合理。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>關係人交易規模雖大但屬半導體產業鏈正常現象。定價公允、付款紀律、子公司交易均無異常。主要風險為Kioxia集中度但已長期存在。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>年報數據：2025_Q4_6239_合併.pdf (pages 67-70，關係人交易附註)</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 75-76，資金貸與及主要股東)</li><li>年報數據：2025_Q4_6239_合併.pdf (page 48，股本及股權結構)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const p=e(t,[["render",l]]);export{u as __pageData,p as default};
